// 1. Verifica se o corpo da requisição e os dados existem
const body = $json.body;
if (!body || !body.data || !body.data.key) {
  return []; // Aborta silenciosamente se não for uma mensagem válida
}

const data = body.data;

// 2. Ignorar se for grupo ou se fui eu que mandei (fromMe)
if (data.key.remoteJid.includes('@g.us') || data.key.fromMe) {
  return [];
}

// 3. Extrair texto da mensagem (considerando diferentes tipos na v2)
const messageText = data.message?.conversation || 
                    data.message?.extendedTextMessage?.text || 
                    data.message?.buttonsResponseMessage?.selectedButtonId || "";

// 4. Normalizar Telefone para busca no Airtable
// Remove o @s.whatsapp.net e limpa caracteres não numéricos
const phone = data.key.remoteJid.split('@')[0].replace(/\D/g, '').replace(/^55/, '');

return {
  phone,
  messageText,
  remoteJid: data.key.remoteJid,
  pushName: data.pushName || "Cliente"
};

// Cálculo de tempo humano: ~30 caracteres por segundo + um atraso base
const text = $node["VENDEDORA LETICIA"].json.output; // Referência ao texto gerado [cite: 133]
const textLength = text.length;

// Fórmula: (Comprimento / Constante de Velocidade) + Tempo de Pensar (aleatório)
// Para 200 caracteres, resultará em aprox. 5 a 7 segundos
const waitTime = Math.floor((textLength / 35) + (Math.random() * (4 - 2) + 2));

return {
  waitTimeSeconds: waitTime,
  text: text
};
